#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
int M;inline void DN(int &x){x>=M?x-=M:0;}
inline int qpow(int a,int b){int r(1);for(;b;b>>=1,a=1ll*a*a%M)if(b&1)r=1ll*r*a%M;return r;}
const int N=5010;int C[N][N],n,fac[N],ifac[N];
int main()
{
	scanf("%d%d",&n,&M);
	C[0][0]=1;rep(1,n,i){C[i][0]=1;rep(1,i,j)DN(C[i][j]=C[i-1][j-1]+C[i-1][j]);}
	int ans=0;fac[0]=1;rep(1,n,i)fac[i]=1ll*i*fac[i-1]%M,ifac[i]=qpow(fac[i],M-2);
	rep(1,n>>1,x)
	{
		rep(0,n-(x<<1),y)
		{
			ans=(1ll*C[n][y]
					*fac[n-y]%M
					*qpow(n-1,x)%M
					*qpow(n-x-y,y)%M
					*C[n-x-y-1][x-1]%M
					*ifac[x]
					+ans
				)%M;
		}
	}
	printf("%d\n",ans);return 0;
}
